import fs from "node:fs";
import { captureFromHook } from "../chatSessions/index.js";
import { runTrackSkill } from "../commands/trackSkill.js";
import { extractSkillFromPrompt } from "./skillDetection.js";
export { extractSkillFromPrompt };
function readHookInput() {
    try {
        const stdin = fs.readFileSync(0, "utf-8");
        if (!stdin.trim()) {
            return null;
        }
        return JSON.parse(stdin);
    }
    catch {
        return null;
    }
}
/**
 * Entry point for the UserPromptSubmit (Claude Code) / beforeSubmitPrompt
 * (Cursor) hook. Reads the hook payload from stdin, detects Bitfab skill
 * invocations, and emits a server-side `api:plugin_skill_invoke` analytics event via
 * {@link runTrackSkill}. Also forwards the hook to chat session capture.
 * Never throws - telemetry must never block prompt submission.
 */
export async function runUserPromptSubmit(pluginVersion, platform, agent = "claude-code") {
    const input = readHookInput();
    if (!input) {
        return;
    }
    const tasks = [];
    if (input.prompt) {
        const skillName = extractSkillFromPrompt(input.prompt);
        if (skillName) {
            tasks.push(runTrackSkill(skillName, pluginVersion, platform));
        }
    }
    if (input.session_id) {
        tasks.push(captureFromHook("UserPromptSubmit", input, agent, pluginVersion).catch(() => { }));
    }
    await Promise.all(tasks);
}
